#include <vector>
#include <queue>
#include <tuple>
#include <algorithm>

using namespace std;

// Define a structure or use a tuple to store (time, color, row, col)
// We will use a priority queue based approach, similar to Dijkstra's algorithm, 
// but here the "cost" is the time (distance), and we prioritize higher color upon tie.

// Structure to hold state for the priority queue
struct State {
    long long time;
    int color;
    int r;
    int c;

    // Overload the comparison operator for the min-heap behavior of std::priority_queue 
    // when used to simulate a specific order.
    // We want the state that reaches a cell first (minimum time) to be prioritized.
    // If times are equal, we want the state with the maximum color to be prioritized
    // to correctly implement the rule: "If multiple colors reach simultaneously, 
    // the cell takes the maximum color."
    bool operator>(const State& other) const {
        if (time != other.time) {
            return time > other.time; // Min-heap on time
        }
        // If times are equal, prioritize larger color (so that larger color is popped first 
        // when we are updating a cell at the same time step).
        return color < other.color; // Max-heap on color among equal times
    }
};

/**
 * @brief Solves the color diffusion problem using a multi-source BFS approach (Dijkstra-like).
 * 
 * @param n The number of rows.
 * @param m The number of columns.
 * @param sources Initial colored cells [r_i, c_i, color_i].
 * @return std::vector<std::vector<long long>> The final state of the grid.
 */
vector<vector<long long>> solve(long long n, long long m, vector<vector<long long>>& sources) {
    // Initialize the result grid. 0 means uncolored.
    vector<vector<long long>> grid(n, vector<long long>(m, 0));

    // Min-priority queue based on State::operator>
    priority_queue<State, vector<State>, greater<State>> pq;

    // 1. Initialize sources
    for (const auto& source : sources) {
        int r = source[0];
        int c = source[1];
        int color = (int)source[2];

        // Grid stores the final color. We use 0 for uncolored, and color > 0 otherwise.
        // Since the initial sources are the start, they are effectively at time 0.
        // We store the color directly in the grid initially.
        grid[r][c] = color;

        // Push initial state: time 0, initial color, position
        pq.push({0, color, r, c});
    }

    // Directions: Up, Down, Left, Right
    int dr[] = {-1, 1, 0, 0};
    int dc[] = {0, 0, -1, 1};

    // 2. Process using modified BFS/Dijkstra
    // The grid will eventually store the final, correct color.
    // The PQ ensures that we process the event (color reaching a cell) 
    // that happens earliest in time. If times are equal, we process the 
    // higher color first, which correctly sets the maximum color rule.

    while (!pq.empty()) {
        State current = pq.top();
        pq.pop();

        long long time = current.time;
        int color = current.color;
        int r = current.r;
        int c = current.c;

        // Check if the color currently in the grid is already 'better' than the 
        // one we are processing (i.e., reached at an earlier time, or same time but higher color).
        // Because we process based on (time ascending, color descending), if the grid 
        // already has a color, it means a path has already established that color.

        // A simpler check in this specific problem: 
        // If the grid already has a color, and that color is different from current.color, 
        // OR if the current time is greater than the time associated with the color in the grid,
        // we might need more complex tracking.

        // However, since the grid stores only the *final* color, and we are simulating 
        // the *propagation* step-by-step, we must ensure we only update if the new color
        // is superior *at the time it arrives*.

        // In this Dijkstra setup, we rely on the fact that the first time we extract 
        // a state (t, c, r, c) from the PQ, it represents the fastest way to reach 
        // (r, c) with color 'c' OR the highest color among fastest ways.

        // If the cell (r, c) in the grid already has a color, and this color 
        // was set by an event that arrived at the *same or earlier* time 
        // with a *greater or equal* color, we skip.

        // Since we don't explicitly store time in the grid, we rely on the fact 
        // that if grid[r][c] != color, it means either:
        // 1. It was set by an earlier time (and thus grid[r][c] is the result).
        // 2. It was set by the same time but a higher color (due to PQ ordering).

        // We only need to proceed if the current state represents a color 
        // that is currently dominant or if the cell is uncolored (grid[r][c] == 0).

        if (grid[r][c] != 0 && grid[r][c] != color) {
             // If the cell already has a color that is NOT the color we are processing, 
             // it means a path arrived earlier or with a higher color previously, 
             // OR a path arrived at the same time but we processed the higher color first.
             // Due to the PQ ordering (time min, color max), if grid[r][c] is set, 
             // it must be the final/dominant color already.
             continue;
        }

        // If grid[r][c] == 0, this is the first time we reach it.
        // If grid[r][c] == color, this is a propagation from an existing colored cell.
        // The actual coloring happens when we look at neighbors.

        // Explore neighbors
        for (int i = 0; i < 4; ++i) {
            long long nr_ll = r + dr[i];
            long long nc_ll = c + dc[i];

            // Check boundary conditions
            if (nr_ll >= 0 && nr_ll < n && nc_ll >= 0 && nc_ll < m) {
                int nr = (int)nr_ll;
                int nc = (int)nc_ll;

                // The neighbor must be uncolored *or* be colored by a less dominant color.
                // In this simulation, we check the current state of the neighbor.
                long long neighbor_color = grid[nr][nc];
                long long neighbor_time = -1; // Time doesn't need to be explicitly stored if we rely on PQ extraction order.

                if (neighbor_color == 0) {
                    // Uncolored neighbor: It will definitely take this color at time + 1.
                    // We update the grid *conceptually* by pushing the event, and rely on the 
                    // PQ to resolve conflicts.
                    pq.push({time + 1, color, nr, nc});
                } else {
                    // Already colored neighbor. Check for conflict resolution.
                    // If the neighbor color is DIFFERENT from the color spreading, 
                    // a conflict might happen at time + 1.

                    // This BFS approach is slightly tricky because we don't track arrival time 
                    // for already colored cells, only for uncolored ones.

                    // Key Insight: The PQ structure guarantees that when we process (t, c, r, c), 
                    // this is the fastest/best way to reach (r, c). We use this event 
                    // to propagate to neighbors. If a neighbor (nr, nc) is already colored 
                    // (grid[nr][nc] != 0), it means it was colored by a path that was processed 
                    // earlier or has a higher priority in the PQ. We only propagate to uncolored cells (grid[nr][nc] == 0).

                    // If grid[nr][nc] != 0, we assume it's settled for now, as the PQ processes 
                    // the dominant paths first.
                }
            }
        }
    }

    // Post-processing: The PQ approach above only propagates to truly 0 cells. 
    // We need a final sweep to correctly resolve conflicts based on arrival time + color.

    // Re-implementing with explicit distance/time tracking for all cells

    vector<vector<long long>> final_grid(n, vector<long long>(m, 0));
    // distance[r][c] stores the minimum time to reach (r, c)
    vector<vector<long long>> dist(n, vector<long long>(m, -1)); 
    // color_at_dist[r][c] stores the color that achieved dist[r][c]
    vector<vector<int>> color_at_dist(n, vector<int>(m, 0));

    // Reset PQ for the robust Dijkstra implementation
    priority_queue<State, vector<State>, greater<State>> pq_final;

    for (const auto& source : sources) {
        int r = source[0];
        int c = source[1];
        int color = (int)source[2];

        dist[r][c] = 0;
        color_at_dist[r][c] = color;
        final_grid[r][c] = color; // Initialize grid with source colors

        // Push state: time 0, color, r, c
        pq_final.push({0, color, r, c});
    }

    while (!pq_final.empty()) {
        State current = pq_final.top();
        pq_final.pop();

        long long time = current.time;
        int color = current.color;
        int r = current.r;
        int c = current.c;

        // Check if this state is obsolete (we found a better way to reach this cell already)
        // A state is obsolete if:
        // 1. We reached it faster OR
        // 2. We reached it at the same time but with a higher color.

        // Since the PQ is prioritized (time ASC, color DESC), the *first* time we extract 
        // a state (t, c, r, c) from the queue, it represents the dominant outcome for (r, c)
        // at time t.

        if (time > dist[r][c] || (time == dist[r][c] && color < color_at_dist[r][c])) {
            continue; // Obsolete entry
        }

        // Propagate to neighbors
        for (int i = 0; i < 4; ++i) {
            long long nr_ll = r + dr[i];
            long long nc_ll = c + dc[i];

            if (nr_ll >= 0 && nr_ll < n && nc_ll >= 0 && nc_ll < m) {
                int nr = (int)nr_ll;
                int nc = (int)nc_ll;

                long long new_time = time + 1;
                int new_color = color;

                // Check for update condition:
                // 1. Unvisited (dist == -1)
                // 2. Reached faster (new_time < dist[nr][nc])
                // 3. Reached at same time but with higher color (new_time == dist[nr][nc] && new_color > color_at_dist[nr][nc])

                bool should_update = false;
                if (dist[nr][nc] == -1) {
                    should_update = true;
                } else if (new_time < dist[nr][nc]) {
                    should_update = true;
                } else if (new_time == dist[nr][nc] && new_color > color_at_dist[nr][nc]) {
                    should_update = true;
                }

                if (should_update) {
                    dist[nr][nc] = new_time;
                    color_at_dist[nr][nc] = new_color;

                    // Update the final grid result immediately, as this is the best known state
                    final_grid[nr][nc] = new_color; 

                    pq_final.push({new_time, new_color, nr, nc});
                }
            }
        }
    }

    // Since the Dijkstra/PQ approach correctly settles the best color for every cell 
    // as soon as it's finalized, the final_grid holds the correct answer.
    return final_grid;
}
