#include <vector>
#include <queue>
#include <tuple>
#include <algorithm>

using namespace std;

// Define a structure or tuple for priority queue elements
// We want to prioritize based on time (distance) first (smaller is better),
// then based on color (larger is better for tie-breaking, but the problem is about *arrival time*).
// Since we are doing a multi-source BFS, we are interested in the time it takes for *each* source to reach a cell.
// The crucial rule is: "If multiple colors arrive at the same time step, the cell adopts the color with the maximum value."
// This suggests a variation of Dijkstra's or 0-1 BFS where the "cost" is time, but we must track which color wins.

// A state in our BFS will be (time, color, row, col)
// Since we are spreading layer by layer (time step by time step), a standard BFS is appropriate.

struct State {
    int r, c;
    int time;
    int color;

    // For a priority queue (if we used Dijkstra's, which we might need if arrival times differ significantly)
    // However, since all edge weights (time increments) are 1, a standard queue (BFS) works for time progression.
};

// In this problem, the time is the distance from the source. We use BFS.
// The grid state needs to store: (time_of_arrival, color_of_winner)

// Since the arrival time is the key for layer-by-layer processing, and the color is the tie-breaker,
// we can use a queue and process time steps implicitly or explicitly.

// Let's use a structure to store the best known arrival information for each cell.
struct CellInfo {
    int time = 1e9 + 7; // Initialize with infinity time
    int color = 0;
};

// Directions: Up, Down, Left, Right
const int dr[] = {-1, 1, 0, 0};
const int dc[] = {0, 0, -1, 1};


vector<vector<int64>> solve(int64 n, int64 m, vector<vector<int64>>& sources) {
    int N = (int)n;
    int M = (int)m;

    // Grid to store the final color. Initialize to 0 (uncolored).
    vector<vector<int64>> result_grid(N, vector<int64>(M, 0));

    // Grid to store the earliest time each cell is reached and the color that caused it.
    // We need to store both time and color because if times are equal, color wins.
    // Initialize time to infinity.
    vector<vector<CellInfo>> grid_info(N, vector<CellInfo>(M));

    // BFS Queue: stores {r, c, time, color}
    // Since all initial sources are at time 0, we process them first.
    queue<tuple<int, int, int, int>> q;

    // 1. Initialize sources
    for (const auto& source : sources) {
        int r = (int)source[0];
        int c = (int)source[1];
        int color = (int)source[2];

        if (grid_info[r][c].time > 0) { // Should not happen based on constraints, but good practice
            // This cell was already set by another source (should be impossible by constraints)
        } else {
            grid_info[r][c].time = 0;
            grid_info[r][c].color = color;
            result_grid[r][c] = color;
            // Queue stores {r, c, time, color}
            q.push({r, c, 0, color});
        }
    }

    // 2. BFS Expansion
    while (!q.empty()) {
        auto [r, c, time, color] = q.front();
        q.pop();

        int next_time = time + 1;

        // Explore neighbors
        for (int i = 0; i < 4; ++i) {
            int nr = r + dr[i];
            int nc = c + dc[i];

            // Check boundaries
            if (nr >= 0 && nr < N && nc >= 0 && nc < M) {

                // Check if this new path is better than the current best known path to (nr, nc)

                // Case 1: New time is strictly smaller (always better)
                if (next_time < grid_info[nr][nc].time) {
                    grid_info[nr][nc].time = next_time;
                    grid_info[nr][nc].color = color;
                    result_grid[nr][nc] = color;
                    q.push({nr, nc, next_time, color});
                } 
                // Case 2: New time is equal to current best time (tie-breaker based on color)
                else if (next_time == grid_info[nr][nc].time) {
                    if (color > grid_info[nr][nc].color) {
                        // The new color wins the tie
                        grid_info[nr][nc].color = color;
                        result_grid[nr][nc] = color;

                        // CRITICAL: If the winning color changes at the same time step, 
                        // it might affect future propagation from this cell at next_time+1.
                        // Since we are using BFS layer by layer (time), if a better color reaches 
                        // at the *same* time step, we must re-queue it to ensure its neighbors 
                        // at time+1 get the updated information.
                        q.push({nr, nc, next_time, color});
                    }
                }
                // Case 3: New time is greater (ignore)
            }
        }
    }

    // The result_grid now holds the final colors.
    return result_grid;
}
