#include <vector>
#include <queue>
#include <tuple>
#include <algorithm>

using namespace std;

struct Cell {
    long long r, c;
    int color;
    long long dist;
};

// Custom comparator for the priority queue (Min-Heap based on distance, but we need to handle tie-breaking for color)
// In Dijkstra's context for BFS-like spread, we prioritize shorter distance.
// If distances are equal, the problem states the cell takes the MAX color.
// So, for the priority queue, we want to process states that reach a cell sooner.
// If two states reach the same cell at the same time (same distance), we want the one with the higher color to "win" immediately, 
// or at least ensure that the state that *should* win (higher color) is considered appropriately.
// A standard Dijkstra/BFS approach processes by distance. When distances are equal, the order might matter for the final assignment.

// Let's use a standard BFS structure, but since multiple colors spread simultaneously, we need a mechanism that tracks the best arrival at each cell.

// The problem describes a simultaneous spread:
// In one time step, all colored cells spread to adjacent *uncolored* cells.
// If multiple colors reach the same uncolored cell simultaneously, it takes the max color.

// This suggests a multi-source BFS where the "level" in BFS corresponds to time.
// We need to track the minimum time to reach each cell AND the color that achieves that minimum time (or the maximum color among those achieving minimum time).

// State in the queue: {distance, color, r, c}
// We use a Min-Heap based on distance.

// Since we are looking for the maximum color in case of a tie in time, we can modify the relaxation:
// For a cell (r, c), we store {time, color}. We want to minimize time, and among minimum times, maximize color.

// Let's use a distance array `dist[N][M]` initialized to infinity, and a color array `final_color[N][M]` initialized to 0.

// Since N*M is up to 10^5, we can afford O(N*M log(N*M)) or O(N*M). BFS is O(V+E) = O(N*M).

// We use a Priority Queue for Dijkstra-like behavior, prioritizing minimum distance.
// PQ stores {distance, -color, r, c} to ensure:
// 1. Minimum distance is prioritized (Min-Heap on distance).
// 2. If distances are equal, maximum color is prioritized (Min-Heap on -color).

// The distance is the time taken.

void solve_internal(long long n, long long m, const vector<vector<int>>& sources_int, vector<vector<int>>& result) {
    // dist[r][c]: Minimum time (distance) to reach (r, c)
    // Initialize to a large value (infinity)
    vector<vector<long long>> dist(n, vector<long long>(m, -1)); // Using -1 to represent infinity/unreached initially, as time starts at 0

    // final_color[r][c]: The color assigned to (r, c)
    vector<vector<int>> final_color(n, vector<int>(m, 0));

    // Priority Queue: {distance, -color, r, c}
    // We use std::tuple for PQ comparison. C++'s std::priority_queue is a Max-Heap by default.
    // To simulate a Min-Heap, we store negative distance or use a custom comparator.
    // Since we want min distance, we store {distance, ...} and use greater<>.
    // For tie-breaking (max color), we store {-color, ...} so that larger color (smaller -color) comes first in the Min-Heap.
    using State = tuple<long long, int, int, int>; // {distance, negative_color, r, c}
    priority_queue<State, vector<State>, greater<State>> pq;

    // Initialize sources
    for (const auto& source : sources_int) {
        long long r = source[0];
        long long c = source[1];
        int color = source[2];

        // Initial state: time 0
        if (dist[r][c] == -1 || dist[r][c] > 0) { // Should always be unreached initially, but check for safety
            dist[r][c] = 0;
            final_color[r][c] = color;
            pq.emplace(0, -color, r, c);
        }
    }

    int dr[] = {-1, 1, 0, 0};
    int dc[] = {0, 0, -1, 1};

    while (!pq.empty()) {
        auto [d, neg_c, r, c] = pq.top();
        pq.pop();

        int current_color = -neg_c;

        // If we found a better path already, skip.
        // A state popped from PQ might be stale if a cell was reached faster/with a better color combination already.
        // The criteria for "better" is: smaller distance, or same distance and larger color.

        // If the current state (d, current_color) is worse than the recorded best for (r, c), skip.
        // Recorded best: (dist[r][c], final_color[r][c])

        // If current distance d > dist[r][c], it's worse (slower).
        if (d > dist[r][c]) continue;

        // If current distance d == dist[r][c], but current_color < final_color[r][c], it's worse (smaller color tie-break).
        // Note: If d == dist[r][c] and current_color == final_color[r][c], it's the same state, and processing it again is redundant unless it leads to new neighbors.
        // Since the PQ prioritizes higher color for equal distance, the first one processed for a given distance should be the one with the max color.
        if (d == dist[r][c] && current_color < final_color[r][c]) continue;


        // Explore neighbors
        for (int i = 0; i < 4; ++i) {
            long long nr = r + dr[i];
            long long nc = c + dc[i];
            long long next_d = d + 1;

            if (nr >= 0 && nr < n && nc >= 0 && nc < m) {

                // Check the state of the neighbor (nr, nc)
                long long neighbor_dist = dist[nr][nc];
                int neighbor_color = final_color[nr][nc];

                bool should_update = false;

                if (neighbor_dist == -1) {
                    // Unreached cell: Always update
                    should_update = true;
                } else if (next_d < neighbor_dist) {
                    // Reached strictly faster: Always update
                    should_update = true;
                } else if (next_d == neighbor_dist) {
                    // Reached at the same time: Update if current color is strictly greater
                    if (current_color > neighbor_color) {
                        should_update = true;
                    }
                }

                if (should_update) {
                    dist[nr][nc] = next_d;
                    final_color[nr][nc] = current_color;
                    // Push the new state to PQ
                    pq.emplace(next_d, -current_color, nr, nc);
                }
            }
        }
    }

    // Copy final_color to result
    for (long long i = 0; i < n; ++i) {
        for (long long j = 0; j < m; ++j) {
            result[i][j] = final_color[i][j];
        }
    }
}


// Wrapper function to match the required signature and handle type conversions if necessary
// Since the input signature uses Int64 (long long in C++), we cast internally.
// The provided signature uses Array<Array<Int64>>, which maps to vector<vector<long long>> in C++.
// However, since colors are <= 10^6 (fit in int), and coordinates are up to 10^5, we use int for colors and long long for coordinates/distance.
vector<vector<long long>> solve(long long n, long long m, vector<vector<long long>>& sources) {
    // Convert sources from vector<vector<long long>> to vector<vector<int>> for easier processing, 
    // as colors are small enough for int.
    vector<vector<int>> sources_int;
    for (const auto& s : sources) {
        // s = [r_i, c_i, color_i]
        sources_int.push_back({(int)s[0], (int)s[1], (int)s[2]});
    }

    // Result grid initialization (using long long as per return signature)
    vector<vector<long long>> result(n, vector<long long>(m, 0));

    // Run the core logic
    solve_internal(n, m, sources_int, result);

    return result;
}
